(window.webpackJsonp=window.webpackJsonp||[]).push([[354],{981:function(r,n){r.exports="\x3c!-- \r\ntitle: 内网穿透\r\nsort: \r\n--\x3e \r\n\r\n> 推荐使用[Sakura](https://www.natfrp.com/)\r\n\r\n## 自搭\r\n\r\n> [Release](https://github.com/fatedier/frp/releases)\r\n\r\n```bash\r\nwget https://github.com/fatedier/frp/releases/download/v0.32.0/frp_0.32.0_linux_amd64.tar.gz\r\ntar -zxvf frp_0.32.0_linux_amd64.tar.gz\r\n```\r\n\r\n### 编辑配置\r\n\r\n```ini\r\n# vim frpc.ini\r\n[common]\r\n# 连接端口\r\nbind_port = 7000\r\n# 控制板端口\r\ndashboard_port = 7800\r\n# 连接密码\r\ntoken = passswd_token\r\n# 控制板登录\r\ndashboard_user = name\r\ndashboard_pwd = passwd\r\n```\r\n\r\n### 后台与任务\r\n\r\n## 客户端配置\r\n\r\n```ini\r\n[common]\r\nserver_addr = ip\r\nserver_port = 7000\r\ntoken = passwd_token\r\n \r\n[localhost]\r\ntype = tcp\r\nlocal_ip = 127.0.0.1\r\nlocal_port = 22\r\nremote_port = [make sure you open this port in filrewall]\r\n```"}}]);